SELECT t_push_message.id,
t_mdt_order.order_num,
t_push_message.intro,
t_push_message.other_id,
t_push_message.content,
t_push_message.set_time,
t_push_message.is_read
FROM t_push_message
LEFT JOIN
t_mdt_order
on t_push_message.other_id = t_mdt_order.id
WHERE t_push_message.pesronal_id = #{param2}
AND t_push_message.type = #{param3}
AND t_push_message.message_type = #{param4}
AND t_push_message.is_delete = '0'

    AND t_push_message.content like #{param8}


    AND t_mdt_order.order_num = #{param5}


    AND t_push_message.set_time BETWEEN #{param6} AND #{param7}

ORDER BY t_push_message.is_read ASC,
t_push_message.create_time DESC
